-- Switch the default company.logo to the animated ring mark (ring spins once
-- every 10s, bolt pulses every 5s, prefers-reduced-motion honored). Only rows
-- still holding the static ring default from 0012 are touched, so operators
-- who uploaded their own logo are not affected. company.favicon stays static
-- because most browsers do not animate SVG favicons.

UPDATE settings
SET value = '"data:image/svg+xml;base64,"',
    updated_at = NOW()
WHERE key = 'company.logo'
  AND value = '"data:image/svg+xml;base64,"';
